code = """import json

# 1. Load project names (sorted by forks)
project_names = locals()['var_function-call-18203852382069555326']

# 2. Load project_packageversion mappings
pp_file_path = locals()['var_function-call-12985687494578667030']
with open(pp_file_path, 'r') as f:
    pp_data = json.load(f)

# Map ProjectName -> list of (Name, Version)
proj_to_pkg = {}
for row in pp_data:
    pname = row['ProjectName']
    if pname not in proj_to_pkg:
        proj_to_pkg[pname] = []
    proj_to_pkg[pname].append((row['Name'], row['Version']))

# 3. Load packageinfo details
pi_file_path = locals()['var_function-call-12213139248522191101']
with open(pi_file_path, 'r') as f:
    pi_data = json.load(f)

# Create a set of valid (Name, Version) tuples
valid_packages = set()
for row in pi_data:
    # Check License
    licenses_str = row.get('Licenses', '[]')
    if 'MIT' not in licenses_str:
        continue
        
    # Check Release
    vinfo_str = row.get('VersionInfo', '{}')
    if '"IsRelease": true' not in vinfo_str:
        # strict parsing might be safer but string check is fast
        continue
        
    valid_packages.add((row['Name'], row['Version']))

# 4. Find top 5 projects
final_projects = []
for pname in project_names:
    # Get associated packages
    pkgs = proj_to_pkg.get(pname, [])
    
    # Check if any is valid
    is_valid_project = False
    for pkg in pkgs:
        if pkg in valid_packages:
            is_valid_project = True
            break
            
    if is_valid_project:
        final_projects.append(pname)
        if len(final_projects) >= 5:
            break

print("__RESULT__:")
print(json.dumps(final_projects))"""

